await fetch('/api/users', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ name: 'Alice' })
});

String body = "{\"name\":\"Alice\"}";
HttpPost post = new HttpPost("/api/users");
post.setEntity(new StringEntity(body, ContentType.APPLICATION_JSON));
HttpResponse response = client.execute(post);

DECLARE @body NVARCHAR(MAX) = '{"name":"Alice"}';
EXEC sp_OACreate 'MSXML2.XMLHTTP', @http OUT;
EXEC sp_OAMethod @http, 'Open', NULL, 'POST', '/api/users', 0;
EXEC sp_OAMethod @http, 'setRequestHeader', NULL, 'Content-Type', 'application/json';
EXEC sp_OAMethod @http, 'send', NULL, @body;
